text:
Regular Expressions
A conncise and powerful language for describing patterns within strings (often abbreviated as regex or regexp). The simplest regex patterns consist of letters or numbers that are a direct match.

fruit &lt;- stringr::fruit
stringr::str_view(fruit, "berry")

#&gt;  [6] │ bil&lt;berry&gt;
#&gt;  [7] │ black&lt;berry&gt;
#&gt; [10] │ blue&lt;berry&gt;
#&gt; [11] │ boysen&lt;berry&gt;
#&gt; [19] │ cloud&lt;berry&gt;
#&gt; [21] │ cran&lt;berry&gt;
#&gt; [29] │ elder&lt;berry&gt;
#&gt; [32] │ goji &lt;berry&gt;
#&gt; [33] │ goose&lt;berry&gt;
#&gt; [38] │ huckle&lt;berry&gt;
#&gt; [50] │ mul&lt;berry&gt;
#&gt; [70] │ rasp&lt;berry&gt;
#&gt; [73] │ salal &lt;berry&gt;
#&gt; [76] │ straw&lt;berry&gt;

Metacharacters
Most punctuation characters like ., +, *, [, ], and ? have special meanings in regex. For example, “a…e” will match any string that contains an “a” followed by 3 letters and then an “e”.

stringr::str_view(fruit, "a...e")

#&gt;  [1] │ &lt;apple&gt;
#&gt;  [7] │ bl&lt;ackbe&gt;rry
#&gt; [48] │ mand&lt;arine&gt;
#&gt; [51] │ nect&lt;arine&gt;
#&gt; [62] │ pine&lt;apple&gt;
#&gt; [64] │ pomegr&lt;anate&gt;
#&gt; [70] │ r&lt;aspbe&gt;rry
#&gt; [73] │ sal&lt;al be&gt;rry

Detecting Strings in a Dataset

tibble::tibble(fruit = fruit) |&gt;
  dplyr::mutate(berry = stringr::str_detect(fruit, "berry")) |&gt;
  dplyr::count(berry)

#&gt; # A tibble: 2 × 2
#&gt;   berry     n
#&gt;   &lt;lgl&gt; &lt;int&gt;
#&gt; 1 FALSE    66
#&gt; 2 TRUE     14

The stringr::str_detect function can also be used with dplyr::filter and dplyr::summarize. For example, the code below calculates the total number and proportion of fruits containing the word “berry”.

tibble::tibble(fruit = fruit) |&gt;
  dplyr::summarize(
    berry_sum = sum(stringr::str_detect(fruit, "berry")),
    berry_prop = mean(stringr::str_detect(fruit, "berry")) * 100
  )

#&gt; # A tibble: 1 × 2
#&gt;   berry_sum berry_prop
#&gt;       &lt;int&gt;      &lt;dbl&gt;
#&gt; 1        14       17.5


The stringr::str_subset and stringr::str_which functions are closely related to stringr::str_detect. The stringr::str_subset function returns a character vector with the strings that match and stringr::str_which returns an integer vector with the positions of the strings that match.

Removing and Replacing Values

tibble::tibble(fruit = fruit) |&gt;
  dplyr::filter(stringr::str_detect(fruit, "berry")) |&gt;
  dplyr::mutate(
    prefix = stringr::str_remove(fruit, "berry"),
    asterisk = stringr::str_replace(fruit, "berry", "*")
  )


Use stringr::str_remove_all and stringr::str_replace_all to remove or replace all matches as str_remove and str_replace only remove or replace the first match.

Anchors
Matching the start or end of the string requires an anchor. Use ^ to match the start or $ to match the end of the string.

# All fruits that start with an a
stringr::str_view(fruit, "^a")
#&gt; [1] │ &lt;a&gt;pple
#&gt; [2] │ &lt;a&gt;pricot
#&gt; [3] │ &lt;a&gt;vocado

# All fruits that end with an a
stringr::str_view(fruit, "a$")
#&gt;  [4] │ banan&lt;a&gt;
#&gt; [15] │ cherimoy&lt;a&gt;
#&gt; [30] │ feijo&lt;a&gt;
#&gt; [36] │ guav&lt;a&gt;
#&gt; [56] │ papay&lt;a&gt;
#&gt; [74] │ satsum&lt;a&gt;

Quick Timing: system.time()

# Fitting models for each car type
system.time({
  results &lt;- lapply(rownames(mtcars), function(car) {
    profvis::pause(0.1)
    lm(mpg ~ cyl + wt, data = mtcars[rownames(mtcars) == car, ])
  })
})

#&gt; user  system elapsed
#&gt; 3.194   0.018   3.212

The system.time function returns the user, system, and elapsed time. The user time is the time spent executing your R code (i.e., the computation), the system time is the CPU time spent by the operating system, and the elapsed time is the real-world clock time.

Profiling: Finding Bottlenecks
You can also use the profvis R package to profile larger parts of your code. It works best when you source the file as it ensures you get the best connection between profiling data and source code.

# Read in from source file
f &lt;- function() {
  profvis::pause(0.1)
  g()
  h()
}
g &lt;- function() {
  profvis::pause(0.1)
  h()
}
h &lt;- function() {
  profvis::pause(0.1)
}


profvis::profvis(f())



You can interpret the profvis output by identifying wide bars representing slower code and by exploring the memory column (i.e., allocation issues) and flame graph (i.e., call stack).

Vectorization
Vectorization replaces slow R loops with operations that act on entire vectors at once. Because these functions run in optimized C code, they avoid the overhead of per-element interpretation, often achieving 10–100× faster performance on large datasets while keeping code simpler and cleaner.

# Calculating column means
benchmark2 &lt;- bench::mark(
  for_loop = {
    results &lt;- numeric(ncol(iris[, 1:4]))
    for (i in 1:4) {
      results[i] &lt;- mean(iris[, i])
    }
  },
  vectorized = {
    results &lt;- colMeans(iris[, 1:4])
  },
  check = FALSE,
  iterations = 100
)

benchmark2[, c("expression", "median", "itr/sec", "mem_alloc", "n_itr")]

#&gt; A tibble: 2 × 5
#&gt;   expression   median `itr/sec` mem_alloc n_itr
#&gt;   &lt;bch:expr&gt; &lt;bch:tm&gt;     &lt;dbl&gt; &lt;bch:byt&gt; &lt;int&gt;
#&gt; 1 for_loop    867.4µs     1012.   14.04KB    99
#&gt; 2 vectorized   25.9µs    36263.    4.73KB   100

Pre-allocation
Pre-allocation reserves the full size of a vector or data frame before filling it. Without it, R must repeatedly copy and resize the object as it grows, which is costly. By allocating once and updating in place, you avoid unnecessary memory copies and greatly improve speed.

benchmark3 &lt;- bench::mark(
  preallocation = {
    n &lt;- nrow(mtcars)
    mpg_per_cyl &lt;- numeric(n)
    for (i in 1:n) {
      mpg_per_cyl[i] &lt;- mtcars$mpg[i] / mtcars$cyl[i]
    }
  },

  no_preallocation = {
    mpg_per_cyl &lt;- c()
    for (i in 1:nrow(mtcars)) {
      mpg_per_cyl[i] &lt;- mtcars$mpg[i] / mtcars$cyl[i]
    }
  },

  vectorized = {
    mpg_per_cyl &lt;- mtcars$mpg / mtcars$cyl
  },

  check = FALSE,
  iterations = 100,
  memory = TRUE
)

benchmark3[, c("expression", "median", "itr/sec", "mem_alloc", "n_itr")]

#&gt; A tibble: 3 × 5
#&gt;   expression         median `itr/sec` mem_alloc n_itr
#&gt;   &lt;bch:expr&gt;       &lt;bch:tm&gt;     &lt;dbl&gt; &lt;bch:byt&gt; &lt;int&gt;
#&gt; 1 preallocation      1.04ms      944.    23.4KB    98
#&gt; 2 no_preallocation   1.07ms      922.      28KB    98
#&gt; 3 vectorized          738ns  1243766.      304B   100

Processing Accelerometer Data Example

data &lt;- MoveKC::read_agd(system.file(
  "extdata/example5sec.agd",
  package = "agcounts"
))

benchmark4 &lt;- bench::mark(
  preallocation = {
    activity_counts &lt;- data.frame()
    for (i in 1:nrow(data)) {
      if (data$` Axis1`[i] &gt; 200) {
        activity_counts &lt;- rbind(activity_counts, data[i, ])
      }
    }
  },
  vectorized = {
    activity_counts &lt;- data[data$` Axis1`[i] &gt; 200, ]
  },
  check = FALSE,
  iterations = 100
)

benchmark4[, c("expression", "median", "itr/sec", "mem_alloc", "n_itr")]

#&gt; A tibble: 2 × 5
#&gt;   expression      median `itr/sec` mem_alloc n_itr
#&gt;   &lt;bch:expr&gt;    &lt;bch:tm&gt;     &lt;dbl&gt; &lt;bch:byt&gt; &lt;int&gt;
#&gt; 1 preallocation   2.57ms      385.   84.34KB    97
#&gt; 2 vectorized     36.28µs    26759.    7.11KB   100

Use Appropriate Data Structures
Choosing the right data structure dramatically affects performance. The vector search using %in% is fastest because it’s implemented in optimized C code and fully vectorized. The hash table (environment) is much quicker than a named list because it performs constant- time key lookups instead of sequential name scans. However, for large, repeated membership dchecks, %in% still wins due to its low-level vectorized design.

participant_ids &lt;- paste0("P", sprintf("%05d", 1:5000))

set.seed(123)
records_to_check &lt;- sample(
  c(participant_ids, paste0("P", 10000:15000)),
  50000,
  replace = TRUE
)

# Create lookup structures
id_vector &lt;- participant_ids
id_list &lt;- setNames(
  as.list(rep(TRUE, length(participant_ids))),
  participant_ids
)

# --- Hash table version using environment (fastest base-R option)
id_hash &lt;- new.env(hash = TRUE, parent = emptyenv())
for (id in participant_ids) {
  id_hash[[id]] &lt;- TRUE
}

# Benchmark
benchmark5 &lt;- bench::mark(
  named_list = {
    vapply(records_to_check, function(id) !is.null(id_list[[id]]), logical(1))
  },

  hash_env = {
    valid &lt;- vapply(
      records_to_check,
      function(id) !is.null(id_hash[[id]]),
      logical(1)
    )
  },

  vector_search = {
    valid &lt;- records_to_check %in% id_vector
  },

  check = FALSE,
  iterations = 25
)

benchmark5[, c("expression", "median", "itr/sec", "mem_alloc", "n_itr")]

#&gt; A tibble: 3 × 5
#&gt;   expression      median `itr/sec` mem_alloc n_itr
#&gt;   &lt;bch:expr&gt;    &lt;bch:tm&gt;     &lt;dbl&gt; &lt;bch:byt&gt; &lt;int&gt;
#&gt; 1 named_list     990.3ms      1.01     204KB    15
#&gt; 2 hash_env        18.2ms     54.3      204KB    15
#&gt; 3 vector_search    687µs   1437.       885KB    25

Avoid Unnecessary Copies
In R, modifying a data frame can trigger copy-on-modify, creating multiple copies if done repeatedly. Vectorized operations or replacing entire columns at once minimize copying, making code faster, more memory-efficient, and scalable.

df &lt;- mtcars[rep(1:nrow(mtcars), 500), ] # 16,000 rows
cols_to_scale &lt;- c("mpg", "disp", "hp", "drat", "wt")

benchmark6 &lt;- bench::mark(
  iterative_copy = {
    df_copy &lt;- df
    for (col in cols_to_scale) {
      df_copy[[col]] &lt;- scale(df_copy[[col]])
    }
  },

  vectorized = {
    df_copy &lt;- df
    df_copy[cols_to_scale] &lt;- lapply(df_copy[cols_to_scale], scale)
  },
  check = FALSE,
  iterations = 100
)

benchmark6[, c("expression", "median", "itr/sec", "mem_alloc", "n_itr")]

#&gt; A tibble: 2 × 5
#&gt;   expression       median `itr/sec` mem_alloc n_itr
#&gt;   &lt;bch:expr&gt;     &lt;bch:tm&gt;     &lt;dbl&gt; &lt;bch:byt&gt; &lt;int&gt;
#&gt; 1 iterative_copy   2.19ms      388.    7.04MB    74
#&gt; 2 vectorized       1.39ms      730.    7.02MB    71

Writing Functions in C++
Use Rcpp when R code is too slow to vectorize — such as loops, recursion, or complex iterative algorithms. C++ lets you modify data directly and avoid R’s overhead. However, if your task is already vectorized in R, Rcpp won’t add much benefit.

set.seed(123)

bmi &lt;- data.frame(
  weight = round(rnorm(80, mean = 68, sd = 10), 1),
  height = round(rnorm(80, mean = 1.7, sd = 0.3), 1)
)

Rcpp::cppFunction(
  '
NumericVector calculate_bmi_mean_cpp(NumericVector weight, NumericVector height) {
  int n = weight.size();
  NumericVector bmi(n);

  for (int i = 0; i &lt; n; i++) {
    bmi[i] = weight[i] / (height[i] * height[i]);
  }

  return bmi;
}
'
)

benchmark8 &lt;- bench::mark(
  rcpp = {
    calculate_bmi_mean_cpp(bmi$weight, bmi$height)
  },
  vectorized = {
    bmi$weight / bmi$height^2
  },
  preallocation = {
    # bmires &lt;- numeric(length = nrow(bmi))
    bmires &lt;- numeric(length = nrow(bmi))
    for (i in 1:length(bmires)) {
      bmires[i] &lt;- bmi[i, "weight"] / bmi[i, "height"]^2
    }
    bmires
  },
  iterations = 100,
  time_unit = "µs"
)

benchmark8[, c("expression", "median", "itr/sec", "mem_alloc", "n_itr")]

# A tibble: 3 × 5
#&gt;   expression     median `itr/sec` mem_alloc n_itr
#&gt;   &lt;bch:expr&gt;      &lt;dbl&gt;     &lt;dbl&gt; &lt;bch:byt&gt; &lt;int&gt;
#&gt; 1 rcpp             1.93µs   150780.      688B   100
#&gt; 2 vectorized       1.07µs   898683.      688B   100
#&gt; 3 preallocation    1650µs      548.    25.9KB    99


The Rcpp package provides R functions as well as C++ classes which offer a seamless integration of R and C++. It allows you to write a function in C++ and immediately use it within your R script.

Customizing Evaluation with Functions
You can also bind names to functions when evaluating which can allow you to override the behavior of existing functions. For example, we can override the * and + function to work with strings.

add_string &lt;- function(x) {
  e &lt;- rlang::env(
    rlang::caller_env(),
    `+` = function(x, y) paste0(x, y)
  )
  eval(rlang::enexpr(x), e)
}

name &lt;- "Brian"
add_string("Hello " + name)
#&gt; [1] "Hello Brian"

The dplyr package uses this idea to run code in an environment to generate SQL for execution in a remote database.

con &lt;- DBI::dbConnect(RSQLite::SQLite(), filename = ":memory:")
mtcars_db &lt;- dplyr::copy_to(con, mtcars)

mtcars_db |&gt;
  dplyr::filter(cyl &gt; 2) |&gt;
  dplyr::select(mpg:hp) |&gt;
  head(10) |&gt;
  dplyr::show_query()

#&gt; &lt;SQL&gt;
#&gt; SELECT `mpg`, `cyl`, `disp`, `hp`
#&gt; FROM `mtcars`
#&gt; WHERE (`cyl` &gt; 2.0)
#&gt; LIMIT 10

DBI::dbDisconnect(con)

Quosures
A problem arises with with2 in that the expression is evaluated inside of the function and not the environment where it was written. We can solve this problem by using a new data structure called a quosure which bundles the expression with an environment.

with2 &lt;- function(df, expr, method) {
  a &lt;- 1000
  if (method == "enexpr") {
    rlang::eval_tidy(rlang::enexpr(expr), df)
  } else if (method == "enquo") {
    rlang::eval_tidy(rlang::enquo(expr), df)
  }
}

df &lt;- data.frame(x = 1:5)
a &lt;- 10

with2(df, x + a, method = "enexpr")
#&gt; [1] 1001 1002 1003 1004 1005

with2(df, x + a, method = "enquo")
#&gt; [1] 11 12 13 14 15

Application: source()
A simple version of source can be created by combining eval and parse_expr. The source2 function below reads the file from disk, uses parse_expr to parse the string into a list of expressions, and then eval to evaluate each element.

source2 &lt;- function(path, env = rlang::caller_env()) {
  file &lt;- paste(readLines(path, warn = FALSE), collapse = "\n")
  exprs &lt;- rlang::parse_exprs(file)
  res &lt;- NULL
  for (i in seq_along(exprs)) {
    res &lt;- eval(exprs[[i]], env)
  }
  invisible(res)
}

Parent Environments


Every environment has a parent environment. This is used to implement lexical scoping, allowing R to look for values in the parent environment if they are not found in the current one.



You can set a parent environment by providing an unnamed argument to the env() function and identify the parent of an environment with env_parent.

e2a &lt;- rlang::env(d = 4, e = 5)
e2b &lt;- rlang::env(e2a, a = 1, b = 2, c = 3)

rlang::env_parent(e2b)
#&gt; &lt;environment: 0x11b0e5ac0&gt;

identical(rlang::env_parent(e2b), e2a)
#&gt; [1] TRUE

rlang::env_parent(e2a)
#&gt; &lt;environment: R_GlobalEnv&gt;



The only environment that does not have a parent is the empty environment. The ancestors of every environment eventually terminate with the empty environment.




e2c &lt;- rlang::env(rlang::empty_env(), d = 4, e = 5)
e2d &lt;- rlang::env(e2c, a = 1, b = 2, c = 3)

rlang::env_parents(e2b)
#&gt; [[1]]   &lt;env: 0x13dcc5250&gt;
#&gt; [[2]] $ &lt;env: global&gt;

rlang::env_parents(e2d)
#&gt; [[1]]   &lt;env: 0x13dd654f0&gt;
#&gt; [[2]] $ &lt;env: empty&gt;

By default, env_parents will stop at the global environment as the ancestors of the global environment include all attached packages.

rlang::env_parents(e2b, last = rlang::empty_env())

#&gt;  [[1]]   &lt;env: 0x113640f70&gt;
#&gt;  [[2]] $ &lt;env: global&gt;
#&gt;  [[3]] $ &lt;env: tools:rstudio&gt;
#&gt;  [[4]] $ &lt;env: tools:positron&gt;
#&gt;  [[5]] $ &lt;env: package:stats&gt;
#&gt;  [[6]] $ &lt;env: package:graphics&gt;
#&gt;  [[7]] $ &lt;env: package:grDevices&gt;
#&gt;  [[8]] $ &lt;env: package:utils&gt;
#&gt;  [[9]] $ &lt;env: package:datasets&gt;
#&gt; [[10]] $ &lt;env: package:methods&gt;
#&gt; [[11]] $ &lt;env: Autoloads&gt;
#&gt; [[12]] $ &lt;env: package:base&gt;
#&gt; [[13]] $ &lt;env: empty&gt;

Recursing over environments
Operating on every ancestor of an environment is possible with recursive functions. For example, writing a function like where can be used to find the environment of a given name using R’s scoping rules.

where &lt;- function(name, env = rlang::caller_env()) {
  if (identical(env, rlang::empty_env())) {
    stop("Can't find ", name, call. = FALSE)
  } else if (rlang::env_has(env, name)) {
    env
  } else {
    where(name, rlang::env_parent(env))
  }
}

# The base case
where("yyy")
#&gt; Error: Can't find yyy

# The successful case
x &lt;- 5
where("x")
#&gt; &lt;environment: R_GlobalEnv&gt;

# The recursive case
where("mean")
#&gt; &lt;environment: base&gt;

Iteration Instead of Recursion
The same where function can be rewritten with a while loop. We don’t often use recursion, so it may be easier to understand through iteration.

where &lt;- function(name, env = rlang::caller_env()) {
  while (!identical(env, rlang::empty_env())) {
    if (rlang::env_has(env, name)) {
      return(env)
    } else {
      env &lt;- rlang::env_parent(env)
    }
  }
}

e4a &lt;- rlang::env(rlang::empty_env(), a = 1, b = 2)

e4b &lt;- rlang::env(e4a, x = 10, a = 11)

# Finds a in environment e4b
identical(where("a", e4b), e4b)
#&gt; [1] TRUE

# Finds b in parent environment e4a
identical(where("b", e4b), e4a)
#&gt; [1] TRUE

Execution environments


A new environment is created to host execution every time a function is called. This is the execution environment and its parent is the function environment.
Take this function as an example:

h &lt;- function(x) {
  # 1.
  a &lt;- 2 # 2.
  x + a
}

y &lt;- h(1) # 3.

The execution environment is garbage collected once the function completes.



There are a few ways to make the function environment stay around. First, you can explicitly return the environment.

h2 &lt;- function(x) {
  a &lt;- x * 2
  rlang::current_env()
}

e &lt;- h2(x = 10)

rlang::env_print(e)

#&gt; &lt;environment: 0x13278ad98&gt;
#&gt; Parent: &lt;environment: global&gt;
#&gt; Bindings:
#&gt; • a: &lt;dbl&gt;
#&gt; • x: &lt;dbl&gt;

Second, you can return an object with a binding to that environment. The following example uses a function factory (i.e., a function that makes functions) to illustrate that idea.

plus &lt;- function(x) {
  function(y) x + y
}

plus_one &lt;- plus(1)

plus_one

#&gt; function(y) x + y
#&gt; &lt;environment: 0x134575ba0&gt;

plus_one(2)
#&gt; [1] 3



The enclosing environment of plus_one is the execution environment of plus in this function factory.
When plus_one is run, its execution environment captures the execution environment of plus.

Ignoring Conditions
A simple way to handle conditions in R is to ignore them. This can be done using try for errors, suppressWarnings for warnings, and suppressMessages for messages.
The try() function allows execution to continue after an error has occurred.

f1 &lt;- function(x) {
  try(log(x))
  10
}

f1()

#&gt; Error in log(x) : argument "x" is missing, with no default
#&gt; [1] 10

By doing assignment within the call, you can define a default value for use if the code does not work. This works because the argument is evaluated in the calling environment and not the function.

default &lt;- NULL

try(default &lt;- read.csv("this-file-does-not-exist.csv"), silent = TRUE)

Both suppressWarnings() and suppressMessages() suppress all warnings and messages.

suppressWarnings({
  warning("This might be a problem!")
  1
})
#&gt; [1] 1

suppressMessages({
  message("Greetings!")
  2
})
#&gt; [1] 2

Handling Conditions
Each signalling condition has a default behavior:

Errors stop execution and return to the top level
Warnings are captured and displayed in aggregate
Messages are immediately shown

Condition handlers allow us to temporarily override or supplement the default behavior. We can use tryCatch and withCallingHandlers to register handlers.

tryCatch(
  error = function(condition) {
    # code to run when an error is thrown
  },
  # code to run while handlers are active
)

withCallingHandlers(
  warning = function(condition) {
    # code to run when a warning is signalled
  },

  message = function(condition) {
    # code to run when a message is signalled
  },

  # code to run while handlers are active
)

Exiting Handlers
The function tryCatch can be used to handle error conditions. You can override the default error behavior (e.g., return NA instead of an error) and code executes normally if no error exists.

f2 &lt;- function(x) {
  tryCatch(
    error = function(cnd) NA,
    log(x)
  )
}

f2("x")
#&gt; [1] NA

f2(10)
#&gt; [1] 2.302585


It is called an exiting handler because control passes to the handler after the error occurs and never returns to the original code.

The handler functions are called with a single argument (i.e., the condition object). This object becomes more useful when you make your own custom conditions.

tryCatch(
  error = function(cnd) {
    paste0("--", conditionMessage(cnd), "--")
  },
  stop("Here is an error")
)

#&gt; [1] "--Here is an error--"

The tryCatch function also has a finally argument to provide a block of code that runs regardless of whether the initial expression is successful. This could be useful for clean up (e.g., deleting files) or closing connections.

path &lt;- tempfile()

tryCatch(
  {
    writeLines("Hi", path)
  },
  finally = {
    unlink(path)
  }
)

Custom Conditions
R has the ability to create custom conditions containing additional metadata. Using rlang::abort allows you to apply a custom .subclass and additional metadata, guiding the user toward a solution to the problem.

my_log &lt;- function(x, base = exp(1)) {
  if (!is.numeric(x)) {
    rlang::abort(
      paste0(
        "`x` must be a numeric vector; not ",
        typeof(x),
        "."
      )
    )
  }
  if (!is.numeric(base)) {
    rlang::abort(
      paste0(
        "`base` must be a numeric vector; not ",
        typeof(base),
        "."
      )
    )
  }
  base::log(x, base = base)
}

my_log(letters)
#&gt; Error in `my_log()`: `x` must be a numeric vector; not character.

my_log(1:10, base = letters)
#&gt; Error in `my_log()`: `base` must be a numeric vector; not character.

Signalling
Let’s improve our my_log error handling by making it more generalized, including a nice error message with the glue R package for the user and more metadata for the developer.

# An example of doing this in Base R is in Advaned R on page 191

abort_bad_argument &lt;- function(arg, must, not = NULL) {
  msg &lt;- glue::glue("`{arg}` must {must}")
  if (!is.null(not)) {
    not &lt;- typeof(not)
    msg &lt;- glue::glue("{msg}; not {not}")
  }
  rlang::abort(
    "error_bad_argument",
    message = msg,
    arg = arg,
    must = must,
    not = not
  )
}

my_log &lt;- function(x, base = exp(1)) {
  if (!is.numeric(x)) {
    abort_bad_argument("x", must = "be numeric", not = x)
  }
  if (!is.numeric(base)) {
    abort_bad_argument("base", must = "be numeric", not = base)
  }
  base::log(x, base = base)
}

my_log(letters)
#&gt; Error in `abort_bad_argument()`: ! `x` must be numeric; not character

my_log(1:10, base = letters)
#&gt; Error in `abort_bad_argument()`: ! `base` must be numeric; not character


This structure makes programming more efficient and can be used in a wide range of scenarios including unit testing in package development.

Success and Failure Values
An extension of the failure value by returning a different value if the code evaluates successfully. This requires an evaluation of the code supplied by the user.
We can use this to determine if an expression fails:

does_error &lt;- function(expr) {
  tryCatch(
    error = function(cnd) TRUE,
    {
      expr
      FALSE
    }
  )
}

does_error(log(10))
#&gt; [1] FALSE

does_error(log("x"))
#&gt; [1] TRUE

Or to capture any condition as seen in rlang::catch_cnd

catch_cnd &lt;- function(expr) {
  tryCatch(
    condition = function(cnd) cnd,
    {
      expr
      NULL
    }
  )
}

catch_cnd(log("x"))
#&gt; &lt;simpleError in log("x"): non-numeric argument to mathematical function&gt;

catch_cnd(log(10))
#&gt; NULL

We can also create a variant of the try function that returns a list consisting of a result and error component.

safety &lt;- function(expr) {
  tryCatch(
    error = function(cnd) {
      list(result = NULL, error = cnd)
    },
    list(result = expr, error = NULL)
  )
}

safety(log("x"))
#&gt; $result
#&gt; NULL

#&gt; $error
#&gt; &lt;simpleError in log("x"): non-numeric argument to mathematical function&gt;

safety(log(10))
#&gt; $result
#&gt; [1] 2.302585

#&gt; $error
#&gt; NULL

No Default Behavior
You can signal a condition that does not inherit from a message, warning, or error. In this case, there is no default behavior and the condition has no effect unless the user requests it. For example, you could create a logging system based on conditions:

log &lt;- function(message, level = c("info", "error", "fatal")) {
  level &lt;- match.arg(level)
  rlang::signal(message, "log", level = level)
}

log("This code was run")

The condition is signalled, but nothing happens with the code above as it has no default handler. To activate logging, you need a handler that does something with the log condition.

record_log &lt;- function(expr, path = stdout()) {
  withCallingHandlers(
    log = function(cnd) {
      cat(
        "[",
        cnd$level,
        "] ",
        cnd$message,
        "\n",
        sep = "",
        file = path,
        append = TRUE
      )
    },
    expr
  )
}

record_log(log("Hello"))
#&gt; [info] Hello

You could even add another function to selectively ignore some logging levels.

ignore_log_levels &lt;- function(expr, levels) {
  withCallingHandlers(
    log = function(cnd) {
      if (cnd$level %in% levels) {
        rlang::cnd_muffle(cnd)
      }
    },
    expr
  )
}

record_log(ignore_log_levels(log("Hello"), "info"))

If, Else, and Else If
A basic if statement will evaluate if some expression is true or false and then execute a specific task if the expression is true.

x &lt;- 10
if (x &gt; 5) {
  print("x is greater than 5")
}
# [1] "x is greater than 5"

y &lt;- 3
if (y &gt; 5) {
  print("y is greater than 5")
}
# [1]

To enhance the if statement, you can add an else condition. This means that the true_action is evaluated if the condition is TRUE and the false_action is evaluated if the condition is FALSE.

if (y &gt; 5) {
  print("y is greater than 5")
} else {
  print("y is less than 5")
}
#[1] "y is less than 5"

Using else if allows you to make a chain of statements where each input is evaluated through this chain of statements. This means that you are giving a list of conditions and seeing which matches your input. The actions are often compound statements contained within { and returns a value so you can assign the results.

grade &lt;- function(x) {
  if (x &gt; 90) {
    "A"
  } else if (x &gt; 80) {
    "B"
  } else if (x &gt; 50) {
    "C"
  } else {
    "F"
  }
}

(c(grade(85), grade(98)))
#&gt; [1] "B" "A"

Switch Statements
The switch() function in R is a more compact alternative to writing long chains of if, else if, and else conditions when you are comparing a single input to several known options.
Instead of checking conditions one by one, switch() directly matches the input to a predefined list of values and returns the associated result. Compare this example using else if:

x_option &lt;- function(x) {
  if (x == "a") {
    "option 1"
  } else if (x == "b") {
    "option 2"
  } else if (x == "c") {
    "option 3"
  } else {
    print("Invalid `x` value")
  }
}
x_option("a")
# [1] "option 1"
x_option("hand")
# [1] "Invalid `x` value"

With this example using switch

x_option &lt;- function(x) {
  switch(
    x,
    a = "option 1",
    b = "option 2",
    c = "option 3",
    stop(
      "Invalid x value"
    )
  )
}
x_option("a")
# [1] "option 1"
x_option("hand")
# [1] "Invalid x value"

With switch statements, if multiple inputs have the same value, you can leave it blank after the = and the input will fall through to the next value.

legs &lt;- function(x) {
  switch(
    x,
    cow = ,
    horse = ,
    dog = 4,
    human = ,
    chicken = 2,
    plant = 0,
    stop("Unknown input")
  )
}

legs("cow")
# [1] 4
legs("dog")
# [1] 4
legs("goat")
#[1] Error in legs("goat") : Unknown input

Pitfall 2: Iterating over 1:length(x)
Attempting to iterate over 1:length(x) will fail in unexpected ways if x has a length of 0. If x is 0, then this is read as 1:0 which is a two element vector [1,0].

daily_avg_steps &lt;- c()

for (i in 1:length(daily_avg_steps)) {
  print(daily_avg_steps[i])
}
# NULL
# NULL

for (i in seq_along(daily_avg_steps)) {
  print(daily_avg_steps[i])
}

Attributes
Functions may have different attributes like srcref short for source reference. It points to the source code used to create the function and is used for printing because it contains code comments and other formatting.

f02 &lt;- function(x, y) {
  # A comment
  x + y
}

attr(f02, "srcref")

#&gt; function(x, y){
#&gt;   # A comment
#&gt;   x + y
#&gt; }

A fresh start
A new environment is created each time a function is called to execute the function.

g07 &lt;- function() {
  if (!exists("a")) {
    a &lt;- 1
  } else {
    a &lt;- a + 1
  }
  a
}

g07()
#&gt; [1] 1

g07()
#&gt; [1] 1

An Example with Sample
This code is from base::sample which takes a sample of the specified size from the elements of x with or without replacement.

The missing function evaluates whether size is given and returns the length of x if it is missing.
This function makes it appear as if x and size are required arguments.


sample &lt;- function(x, size, replace = FALSE, prob = NULL) {
  if (length(x) == 1L && is.numeric(x) && is.finite(x) && x &gt;= 1) {
    if (missing(size)) {
      size &lt;- x
    }
    sample.int(x, size, replace, prob)
  } else {
    if (missing(size)) {
      size &lt;- length(x)
    }
    x[sample.int(length(x), size, replace, prob)]
  }
}

An alternative way to write sample is setting size = NULL in the function arguments to indicate that it is not required. A simpler version of the sample function is to check for NULL.

sample &lt;- function(x, size = NULL, replace = FALSE, prob = NULL) {
  if (is.null(size)) {
    size &lt;- length(x)
  }
  # Or using the `%||%` operator from base R to use the left
  # side if it's not NULL and return the right side otherwise.
  # size &lt;- size %||% length(x)
  x[sample.int(length(x), size, replace, prob)]
}

Exiting a function
Functions exit by returning a value or throwing an error. Returns can be implicit where the last evaluated expression is returned or explicit by calling return.

# Implicit
j01 &lt;- function(x) {
  if (x &lt; 10) {
    0
  } else {
    10
  }
}

j01(9)
#&gt; [1] 0

# Explicit
j02 &lt;- function(x) {
  if (x &lt; 10) {
    return(0)
  } else {
    return(10)
  }
}


Most functions return visibly, but the invisible function prevents automatic printing of the last value. The most common function that returns invisibly is &lt;-.


a &lt;- 2

# You can display visibly with print or by wrapping in ()
print(a &lt;- 2)
#&gt; [1] 2

(a &lt;- 2)
#&gt; [1] 2

Errors
Errors occur when a function cannot complete its assigned task. It uses the stop function to stop the execution of the function.

double &lt;- function(x) {
  if (!is.numeric(x)) {
    stop(sprintf("%s is not numeric", x))
  }
  return(x * 2)
}

double(10)
#&gt; [1] 20

double("10")
#&gt; Error in double("10") : 10 is not numeric

Function Factories
A function factory is a function that makes functions. Here is an example where power makes two child (manufactured) functions (i.e., square, cube).

power1 &lt;- function(exp) {
  function(x) {
    x^exp
  }
}

square &lt;- power1(2)
cube &lt;- power1(3)

square(3)
#&gt; [1] 9
cube(3)
#&gt; [1] 27

Factory Fundamentals
Function factories work because the enclosing environment of the manufactured function is the execution environment of the function factory.

# Printing the square function shows us where x comes from
square
#&gt; function(x){
#&gt;     x ^ exp
#&gt;   }
#&gt; &lt;environment: 0x12a7ebbc0&gt;

# Using env_print shows the binding to exp
rlang::env_print(square)
#&gt; &lt;environment: 0x12a7ebbc0&gt;
#&gt; Parent: &lt;environment: global&gt;
#&gt; Bindings:
#&gt; • exp: &lt;dbl&gt;

# Extract the exp from the enclosure environment of square
rlang::fn_env(square)$exp
#&gt; [1] 2

Stateful Functions
Function factories allow you to maintain state across function calls. This is made possible because the enclosing environment of the manufactured function is unique and constant and the &lt;&lt;- special assignment operator can modify bindings in the enclosing environment.
Here is an example of combining these ideas to create a function that can record how many times it has been called.

new_counter &lt;- function() {
  i &lt;- 0
  function() {
    i &lt;&lt;- i + 1
    i
  }
}

counter_one &lt;- new_counter()

for (i in 1:5) {
  print(counter_one())
}

#&gt; [1] 1
#&gt; [1] 2
#&gt; [1] 3
#&gt; [1] 4
#&gt; [1] 5

Using ggsave
A function factory used internally by ggsave is ggplot2::plot_dev. This helps transition from a file extension (e.g., png, jpeg, etc) to a graphics device function (e.g., png(), jpeg()). There are some inconsistencies with the base graphic devices such as some having filename as the first argument but others having file and a difference in units for width and height between the raster (i.e., pixels) and vector (i.e., inches) graphic devices.

# A simplified version of ggplot2::plot_dev for some image types

plot_dev &lt;- function(ext, dpi = 96) {
  force(dpi)
  switch(
    ext,
    pdf = function(filename, ...) {
      grDevices::pdf(file = filename, ...)
    },
    png = function(...) grDevices::png(..., res = dpi, units = "in"),
    jpg = ,
    jpeg = function(...) grDevices::jpeg(..., res = dpi, units = "in"),
    stop("Unkown graphics extension: ", ext, call. = FALSE)
  )
}

plot_dev("pdf")
#&gt; function(filename, ...) {
#&gt;       grDevices::pdf(file = filename, ...)
#&gt;     }
#&gt; &lt;environment: 0x11c6ed5a8&gt;

plot_dev("png")
#&gt; function(...) grDevices::png(..., res = dpi, units = "in")
#&gt; &lt;bytecode: 0x12d693258&gt;
#&gt; &lt;environment: 0x12f5c7458&gt;

Statistical Factories
Function factories are also a good fit for certain statistical techniques like box-cox transformations, bootstrap resampling, and maximum likelihood estimation (MLE; See Advanced R for MLE example).
The Box-Cox transformation is a type of power transformation often used to transform data toward normality. It takes a single parameter, λ (lambda), to control the strength of the transformation.

# Define boxcox function factory
boxcox &lt;- function(lambda) {
  if (lambda == 0) {
    function(x) log(x)
  } else {
    function(x) (x^lambda - 1) / lambda
  }
}

# Include the function factory in ggplot2::stat_function
stat_boxcox &lt;- function(lambda) {
  ggplot2::stat_function(
    ggplot2::aes(color = lambda),
    fun = boxcox(lambda),
    linewidth = 1
  )
}

# λ = 0: Log transformation
# λ = 1: No transformation
# λ = 0.5: Square-root transformation
# λ = 2: Square transformation

ggplot2::ggplot(data.frame(x = c(0, 5)), ggplot2::aes(x)) +
  lapply(c(0.5, 1, 1.5), stat_boxcox) +
  ggplot2::scale_color_viridis_c(limits = c(0, 1.5))

ggplot2::ggplot(data.frame(x = c(0.01, 1)), ggplot2::aes(x)) +
  lapply(c(0.5, 0.25, 0.1, 0), stat_boxcox) +
  ggplot2::scale_color_viridis_c(limits = c(0, 1.5))

Creating Your Own Function Operator
Imagine you have a named vector of URLs and you want to download each one to your computer. It is simple with purrr::walk2 and utils::file.download().

urls &lt;- c(
  "adv-r" = "https://adv-r.hadley.nz",
  "r4ds" = "https://r4ds.had.co.nz"
)

paths &lt;- paste0(tempdir(), names(urls), ".html")

purrr::walk2(urls, paths, utils::download.file, quiet = TRUE)

This works great for a few URLs, but as the vector gets longer, you might want to add a small delay to avoid overloading the server and display a . every few URLs to know the function is still working. You can do this with a for loop, but the code is harder to read and the components are not reusable in new situations.

for (i in seq_along(urls)) {
  Sys.sleep(0.1)
  if (i %% 10 == 0) {
    cat(".")
  }
  utils::download.file(urls[[i]], paths[[i]])
}

A function operator overcomes the limitations of a for loop and we can create delay_by and dot_every functions that can be reused.

delay_by &lt;- function(f, amount) {
  force(f)
  force(amount)
  function(...) {
    Sys.sleep(amount)
    f(...)
  }
}

dot_every &lt;- function(f, n) {
  force(f)
  force(n)
  i &lt;- 0
  function(...) {
    i &lt;&lt;- i + 1
    if (i %% n == 0) {
      cat(".")
    }
    f(...)
  }
}

purrr::walk2(
  urls,
  paths,
  utils::download.file |&gt; dot_every(10) |&gt; delay_by(0.1),
  quiet = TRUE
)

Validators
More complicated classes require additional checks for validity. A constructor only checks that types are correct, making it possible to create malformed objects.

new_factor &lt;- function(x = integer(), levels = character()) {
  stopifnot(is.integer(x))
  stopifnot(is.character(levels))
  structure(x, levels = levels, class = "factor")
}

new_factor(1:5, "a")
#&gt; Error in `as.character.factor()`: malformed factor

It is better to add checks to a validator rather than including them in the constructor. This allows you to create new objects quickly when you know the values are correct, and re-use the validation checks in other places.

validate_factor &lt;- function(x) {
  values &lt;- unclass(x)
  levels &lt;- attr(x, "levels")
  if (!all(!is.na(values) & values &gt; 0)) {
    stop(
      "All `x` values must be non-missing and greater than zero",
      call. = FALSE
    )
  }
  if (length(levels) &lt; max(values)) {
    stop(
      "There must be at least as many `levels` as possible values in `x`",
      call. = FALSE
    )
  }
  x
}

validate_factor(new_factor(1:5, "a"))
#&gt; Error: There must be at least as many `levels` as possible values in `x`

validate_factor(new_factor(0:1, "a"))
#&gt; Error: All `x` values must be non-missing and greater than zero


The validator function is primarily called for its side-effects (i.e., throwing an error if the object is not valid). It is useful for validation methods to visibly return the original input.

Generics and Methods
An S3 generic chooses the right method for an object’s class (method dispatch). This is done by UseMethod(), which takes the generic’s name and, optionally, the argument to dispatch on. If the second argument is left out (the usual case), it dispatches based on the first argument. Most S3 generics are nothing more than a call to UseMethod().

mean
#&gt; function (x, ...)
#&gt; UseMethod("mean")
#&gt; &lt;bytecode: 0x12f6fb108&gt;
#&gt; &lt;environment: namespace:base&gt;

# Creating your own S3 generic is simple
myNewGeneric &lt;- function(x) {
  UseMethod("myNewGeneric")
}

Allowing Subclassing
If you allow subclasses when creating a class, the parent constructor needs to have ... and class arguments. The subclass constructor can just call to the parent class constructor with additional arguments as needed.

new_secret &lt;- function(x, ..., class = character()) {
  stopifnot(is.double(x))
  structure(x, ..., class = c(class, "secret"))
}

# Create a new supersecret class that hides the number of characters
new_supersecret &lt;- function(x) {
  new_secret(x, class = "supersecret")
}

print.supersecret &lt;- function(x, ...) {
  print(rep("xxxxx", length(x)))
  invisible(x)
}

x2 &lt;- new_supersecret(c(15, 1, 456))
x2
#&gt; [1] "xxxxx" "xxxxx" "xxxxx"

Using the constructor inside methods breaks inheritance (i.e., the result always has the same class, even for subclasses). The vctrs::vec_restore() function restores the original class after operations like subsetting.

# Ignores supersecret class
`[.secret` &lt;- function(x, ...) {
  new_secret(NextMethod())
}

x2[1:3]
#&gt; [1] "xx"  "x"  "xxx"

`[.secret` &lt;- function(x, ...) {
  vctrs::vec_restore(NextMethod(), x)
}

x2[1:3]
#&gt; [1] "xxxxx" "xxxxx" "xxxxx"


If you build your class with vctrs, this behavior comes automatically; you only need a custom [ method for special cases. Explore this package for tools that help create and work with vector-like objects in R

Private
The private argument to R6Class works the same way as the public argument. It accepts a named list of methods (functions) and fields. Fields and methods are available within the class by using private$ instead of self$.

Person &lt;- R6::R6Class(
  classname = "Person",
  public = list(
    initialize = function(name, age = NA) {
      private$name &lt;- name
      private$age &lt;- age
    },
    print = function(...) {
      cat("Person: \n")
      cat("  Name: ", private$name, "\n", sep = "")
      cat("  Age: ", private$age, "\n", sep = "")
    }
  ),
  private = list(
    age = NA,
    name = NULL
  )
)

Brian &lt;- Person$new("Brian", age = 36)
Brian
#&gt; Person:
#&gt;   Name: Brian
#&gt;   Age: 36

Brian$name
#&gt; NULL

Active
Active fields allow you to define components that look like fields, but are defined with functions. They are implemented using active bindings and each active binding is a function that takes a single argument (i.e., value). If the argument is missing(), the value is being retrieved, otherwise it is being modified.

Random &lt;- R6::R6Class(
  classname = "Random",
  active = list(
    random = function(value) {
      if (missing(value)) {
        runif(1)
      } else {
        stop("Can't set `$random`", call. = FALSE)
      }
    }
  )
)

x &lt;- Random$new()

set.seed(123)
x$random
#&gt; [1] 0.2875775

set.seed(456)
x$random
#&gt; [1] 0.0895516

Active fields are particularly useful with private fields as it allows you to implement components that look like fields from the outside but provide additional checks. For example, we can create a read-only age field and to ensure that name is a character vector of length one.

Person &lt;- R6::R6Class(
  classname = "Person",
  private = list(
    .age = NA,
    .name = NULL
  ),
  active = list(
    age = function(value) {
      if (missing(value)) {
        private$.age
      } else {
        stop("`$age` is read only", call. = FALSE)
      }
    },
    name = function(value) {
      if (missing(value)) {
        private$.name
      } else {
        stopifnot(is.character(value), length(value) == 1)
        private$.name &lt;- value
        self
      }
    }
  ),
  public = list(
    initialize = function(name, age = NA) {
      private$.name &lt;- name
      private$.age &lt;- age
    }
  )
)

Brian &lt;- Person$new("Brian", age = 36)
Brian$name
#&gt; [1] "Brian"

Brian$name &lt;- 10
#&gt; Error: is.character(value) is not TRUE

Brian$age &lt;- 35
#&gt; Error: `$age` is read only

Reference Semantics
A difference between R6 and other objects is that they have reference semantics. This means that objects are not copied when modified. Instead, if you want a copy, you need to use $clone(). If you want recursive cloning of nested R6 objects, you will need to use $clone(deep = TRUE).

y1 &lt;- Accumulator$new()

y2 &lt;- y1$clone()

y1$add(10)

c(y1 = y1$sum, y2 = y2$sum)
#&gt; y1 y2
#&gt; 10  0

There are some less obvious consequences of reference semantics:

The $finalize() method should be used to clean up the resources created by the initializer
An R6 class as the default value of a field is shared across all instances of the object

Since R6 objects are not copied-on-modify, they are only deleted one time. We can use $finalize() as a complement to $initialize() as they play a similar role to on.exit in a function and clean up any resources created by the initializer.

TemporaryFile &lt;- R6::R6Class(
  classname = "TemporaryFile",
  public = list(
    path = NULL,
    initialize = function() {
      self$path &lt;- tempfile()
    }
  ),
  private = list(
    finalize = function() {
      message("Cleaning up ", self$path)
      unlink(self$path)
    }
  )
)

tf &lt;- TemporaryFile$new()
rm(tf)
gc()
#&gt; Cleaning up /var/folders/_j/6wfn_8q16dn9f0lq313z__hn_4vjtn/T//Rtmpgqvd1t/file3a385e47c3dc

If you use an R6 class as the default value of a field, it will be shared across all instances of the object. For example, we want to create a temporary database everytime we call TemporaryDatabase$new(), but the code below always uses the same path.

TemporaryDatabase &lt;- R6::R6Class(
  classname = "TemporaryDatabase",
  public = list(
    con = NULL,
    file = TemporaryFile$new(),
    initialize = function() {
      self$con &lt;- DBI::dbConnect(RSQLite::SQLite(), path = file$path)
    }
  ),
  private = list(
    finalize = function() {
      DBI::dbDisconnect(self$con)
    }
  )
)

db_a &lt;- TemporaryDatabase$new()
db_b &lt;- TemporaryDatabase$new()

db_a$file$path == db_b$file$path
#&gt; [1] TRUE

In the example above, TemporaryFile$new() is only called once when TemporaryDatabase is defined. We can move the call to $initialize() to create a new file each time

TemporaryDatabase &lt;- R6::R6Class(
  classname = "TemporaryDatabase",
  public = list(
    con = NULL,
    file = NULL,
    initialize = function() {
      self$file &lt;- TemporaryFile$new()
      self$con &lt;- DBI::dbConnect(RSQLite::SQLite(), path = file$path)
    }
  ),
  private = list(
    finalize = function() {
      DBI::dbDisconnect(self$con)
    }
  )
)

db_a &lt;- TemporaryDatabase$new()
db_b &lt;- TemporaryDatabase$new()

db_a$file$path == db_b$file$path
#&gt; [1] FALSE

Validator
The constructor automatically checks that the slots have the correct classes, but you will need to implement more complicated checks. We can do this with the setValidity function.

setValidity(Class = "Person", method = function(object) {
  if (length(object@name) != length(object@age)) {
    "@name and @age must be the same length"
  } else {
    TRUE
  }
})

Person("Brian", age = c(36, 37))
#&gt; Error in `validObject()`:
#&gt; invalid class “Person” object: @name and @age must be the same length

# Check the validity with validObject
validObject(Person("Brian", age = 36))
#&gt; [1] TRUE
